'''
Solution for question 1 of Rosalind Bioinformatics stronghold
Title: Counting DNA Nucleotides
'''
dna_str=""
A=0
C=0
G=0
T=0
for x in dna_str:
  if x=="A":
    A+=1
  elif x=="C":
    C+=1
  elif x=="G":
    G+=1
  elif x=="T":
    T+=1
'''
Expected output according to the question:
Four integers (separated by spaces) counting the respective number of times that the symbols 'A', 'C', 'G', and 'T' occur in s
'''
print(f"{A} {C} {G} {T}")